- **Install Redux Toolkit and React-Redux Packages**:
  ```bash
  npm install @reduxjs/toolkit react-redux
  ```

- **Create a Redux Store**:
  ```javascript
  import { configureStore } from '@reduxjs/toolkit';
  import rootReducer from './rootReducer';

  const store = configureStore({
    reducer: rootReducer,
  });

  export default store;
  ```

- **Implement useSelector and useDispatch in React Components**:
  ```javascript
  import { useSelector, useDispatch } from 'react-redux';
  import { RootState } from './store'; // Adjust the path to your store

  const MyComponent = () => {
    const data = useSelector((state: RootState) => state.yourReducer.data);
    const dispatch = useDispatch();

    return (
      <div>
        {/* Use data and dispatch */}
      </div>
    );
  };
  ```

- **Latest Versions**:
  - Redux Toolkit: `^1.8.0`
  - React-Redux: `^7.2.6`
